parameters.jsCode:
const datasets = $input.all().map(item => item.json);
const body = $('Webhook').first().json.body;

const datasetContext = datasets.map(d => {
  let mapping = {};
  try {
    mapping = typeof d.column_mapping === 'string' ? JSON.parse(d.column_mapping) : (d.column_mapping || {});
  } catch(e) {}
  const cols = Object.keys(mapping).join(', ');
  return '"' + (d.dataset_name || 'Dataset') + '"\nDescription: ' + (d.dataset_desc || 'N/A') + '\nColumns: ' + (cols || 'N/A');
}).join('\n\n');

return [{
  json: {
    user_prompt: body.prompt,
    dataset_context: datasetContext || 'No dataset information available.'
  }
}];

