        { "text": "by region" },
        { "text": "by month" }
      ]
    },
    {
      "id": "primary_metrics",
      "question": "Which key metrics or KPIs are most important for this report?",
      "hints": [
        { "text": "total revenue" },
        { "text": "order count" },
        { "text": "average order value" }
      ]
    }
  ]
}

